class Solution2 {
public:
    int maxNumberOfFamilies(int n, vector<vector<int>>& reservedSeats) {
        sort(begin(reservedSeats), end(reservedSeats));
        int result = 2 * n;
        for (int i = 0; i < reservedSeats.size();) {
            unordered_map<int, bool> reserved;
            int curr = reservedSeats[i][0];
            while (i < reservedSeats.size() && reservedSeats[i][0] == curr) {
                if (2 <= reservedSeats[i][1] && reservedSeats[i][1] <= 5) {
                    reserved[0] = true;
                }
                if (4 <= reservedSeats[i][1] && reservedSeats[i][1] <= 7) {
                    reserved[1] = true;
                }
                if (6 <= reservedSeats[i][1] && reservedSeats[i][1] <= 9) {
                    reserved[2] = true;
                }
                ++i;
            }
            if (!reserved[0] && !reserved[2]) {
                continue;
            }
            if (!reserved[0] || !reserved[1] || !reserved[2]) {
                --result;
                continue;
            }
            result -= 2;
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)

import collections


class Solution(object):
    def maxNumberOfFamilies(self, n, reservedSeats):
        """
        :type n: int
        :type reservedSeats: List[List[int]]
        :rtype: int
        """
        lookup = collections.defaultdict(lambda: [False]*3)
        for r, c in reservedSeats:
            if 2 <= c <= 5:
                lookup[r][0] = True
            if 4 <= c <= 7:
                lookup[r][1] = True
            if 6 <= c <= 9:
                lookup[r][2] = True
        result = 2*n
        for a, b, c in lookup.itervalues():
            if not a and not c:
                continue
            if not a or not b or not c:
                result -= 1
                continue
            result -= 2
        return result


